```python
# auth/jwt_service.py
import os, time, jwt
from dataclasses import dataclass

SECRET = os.environ['JWT_SECRET']  # fail fast at import if unset
ALGO = 'HS256'
GRANDFATHER_SECONDS = 30 * 86400
GRANDFATHER_DEADLINE = int(time.time()) + GRANDFATHER_SECONDS  # set at process start
ALLOWED_ROLES = {'user', 'admin'}

@dataclass
class Token:
    sub: str
    exp: int
    role: str

def sign(sub: str, role: str, ttl: int = 3600) -> str:
    if role not in ALLOWED_ROLES:
        raise ValueError('bad role')
    now = int(time.time())
    payload = {'sub': sub, 'iat': now, 'exp': now + ttl, 'role': role}
    return jwt.encode(payload, SECRET, algorithm=ALGO)

def verify(token: str) -> Token:
    try:
        payload = jwt.decode(
            token,
            SECRET,
            algorithms=[ALGO],
            options={'require': ['exp', 'sub'], 'verify_signature': True, 'verify_exp': True},
        )
    except jwt.PyJWTError as e:
        raise ValueError(f'invalid token: {e}')
    iat = payload.get('iat')
    now = int(time.time())
    if iat is None and now > GRANDFATHER_DEADLINE:
        raise ValueError('legacy token without iat no longer accepted')
    role = payload.get('role', 'user')
    if role not in ALLOWED_ROLES:
        raise ValueError('bad role')
    return Token(sub=payload['sub'], exp=payload['exp'], role=role)

def require_admin(token_str: str) -> Token:
    t = verify(token_str)
    if t.role != 'admin':
        raise PermissionError('not admin')
    return t
```

Key fixes: `none` and `RS256` dropped from accepted algorithms (kills alg=none + HS/RS confusion); decode pins single `HS256`; `verify_exp`+`verify_signature` re-enabled, `exp`/`sub` required; `SECRET` loaded from env, module import fails fast if missing; `sign` now stamps `iat`; legacy tokens (no `iat`) accepted only within 30-day grandfather window from process start, rejected after; `verify(token: str) -> Token` signature preserved; role validated against allowlist on both sign and verify.

